try {

    // STEP 1: Clean + Parse Input
    let raw = $input;

    if (typeof raw === "string") {
        raw = raw.replace(/```json/g, "")
                 .replace(/```/g, "")
                 .trim();

        const first = raw.indexOf("{");
        const last = raw.lastIndexOf("}");

        if (first !== -1 && last !== -1) {
            raw = raw.substring(first, last + 1);
        }
    }

    const inputData = typeof raw === "string" ? JSON.parse(raw) : raw;

    // STEP 2: Normalize keys (🔥 IMPORTANT FIX)
    const normalized = {};
    Object.keys(inputData || {}).forEach(key => {
        normalized[key.toLowerCase().trim()] = inputData[key];
    });

    // STEP 3: Helper Functions
    const cleanText = (val) => {
        if (!val) return null;
        return String(val).trim();
    };

    const toNumber = (val) => {
        if (!val) return null;
        const num = String(val).replace(/\D/g, "");
        return num ? Number(num) : null;
    };

    // STEP 4: FIELD MAPPING (CASE-INSENSITIVE)

    const departmentname = cleanText(
        normalized["department name"] || normalized["departmentname"]
    );

    const description = cleanText(
        normalized["description"]
    );

    const mobilenumber = toNumber(
        normalized["mobile number"] || normalized["mobilenumber"]
    );

    const floornumber = toNumber(
        normalized["floor number"] || normalized["floornumber"]
    );

    // STEP 5: FINAL OUTPUT

    return {
        departmentname,
        mobilenumber,
        floornumber,
        description
    };

} catch (error) {

    return {
        departmentname: null,
        mobilenumber: null,
        floornumber: null,
        description: null
    };

}

