try {

let raw = $input;

// If input is string, parse it
if (typeof raw === "string") {
    raw = raw.replace(/```json|```/g, "").trim();
    raw = JSON.parse(raw);
}

// Helper functions
const onlyDigits = (val) => val ? String(val).replace(/\D/g, "") : null;

const extractNumber = (val) => {
    if (!val) return null;
    const num = String(val).replace(/\D/g, "");
    return num ? Number(num) : null;
};

const formatDate = (date) => {
    if (!date) return null;

    const parts = date.split(/[\/\-]/);

    if (parts.length === 3) {
        const dd = parts[0].padStart(2,"0");
        const mm = parts[1].padStart(2,"0");
        const yyyy = parts[2];
        return Number(`${yyyy}${mm}${dd}`);
    }

    return null;
};

// Build output
const output = {

patientid: extractNumber(raw["Patient ID"] || raw.patientid),

patientname: raw["Patient Name"] ? raw["Patient Name"].toLowerCase().trim() : null,

patientfathername: raw["Patient Father Name"] ? raw["Patient Father Name"].toLowerCase().trim() : null,

gender: raw["Gender"] ? raw["Gender"].toLowerCase().trim() : null,

dateofbirth: formatDate(raw["DOB of Birth"] || raw["Date of Birth"] || raw.dateofbirth),

bloodgroup: raw["Blood Group"] ? raw["Blood Group"].toLowerCase().trim() : null,

phonenumber: extractNumber(raw["Phone Number"] || raw["Mobile Number"] || raw.phonenumber),

address: raw["Address"] ? raw["Address"].toLowerCase().trim() : null,

city: raw["City"] ? raw["City"].toLowerCase().trim() : null,

state: raw["State"] ? raw["State"].toLowerCase().trim() : null,

pincode: onlyDigits(raw["Pincode"] || raw.pincode),

departmentid: extractNumber(raw["Department"] || raw.departmentid),

assigneddoctorid: extractNumber(raw["Assigned Doctor"] || raw.assigneddoctorid),

registrationdate: formatDate(raw["Registration Date"] || raw.registrationdate),

status: raw["Status"] ? raw["Status"].toLowerCase().trim() : null

};

return output;

} catch (error) {

return {
patientid: null,
patientname: null,
patientfathername: null,
gender: null,
dateofbirth: null,
bloodgroup: null,
phonenumber: null,
address: null,
city: null,
state: null,
pincode: null,
departmentid: null,
assigneddoctorid: null,
registrationdate: null,
status: null
};

}

