try {

    // STEP 1: Clean + Parse Input
    let raw = $input;

    if (typeof raw === "string") {
        raw = raw.replace(/```json/g, "")
                 .replace(/```/g, "")
                 .trim();

        const first = raw.indexOf("{");
        const last = raw.lastIndexOf("}");

        if (first !== -1 && last !== -1) {
            raw = raw.substring(first, last + 1);
        }
    }

    const inputData = typeof raw === "string" ? JSON.parse(raw) : raw;

    // STEP 2: Helpers

    const cleanText = (val) => {
        if (!val) return null;
        return String(val).toLowerCase().trim();
    };

    const toNumber = (val) => {
        if (!val) return null;
        const num = String(val).replace(/\D/g, "");
        return num ? Number(num) : null;
    };

    const toDateNumber = (val) => {
        if (!val) return null;

        let str = String(val).trim();

        if (str.includes("/")) {
            const [dd, mm, yyyy] = str.split("/");
            return Number(yyyy + mm.padStart(2, "0") + dd.padStart(2, "0"));
        }

        if (str.includes("-")) {
            const [yyyy, mm, dd] = str.split("-");
            return Number(yyyy + mm.padStart(2, "0") + dd.padStart(2, "0"));
        }

        return null;
    };

    // 🔥 SMART DROPDOWN NORMALIZATION
    const normalizeDropdown = (val, map) => {
        if (!val) return null;

        const cleaned = String(val).toLowerCase().trim();

        for (const key in map) {
            if (map[key].some(k => cleaned.includes(k))) {
                return key;
            }
        }

        return null;
    };

    // STEP 3: Extract Fields

    const patientid = toNumber(inputData["Patient ID"]);

    const testname = cleanText(inputData["Test Name"]);
    const testdate = toDateNumber(inputData["Test Date"]);

    const referringdoctor = cleanText(inputData["Referring Doctor"]);

    const resultsummary = cleanText(inputData["Result Summary"]);

    // ✅ RENAMED FIELD
    const detailedresultlongtext = cleanText(
        inputData["Detailed Result"] || inputData["Detailed Result (Long Text)"]
    );

    const normalrange = cleanText(inputData["Normal Range"]);

    const resultstatus = normalizeDropdown(
        inputData["Result Status"],
        {
            normal: ["normal"],
            abnormal: ["abnormal", "low", "high"],
            critical: ["critical"]
        }
    );

    const technicianname = cleanText(inputData["Technician Name"]);

    const reportgenerateddate = toDateNumber(inputData["Report Generated Date"]);

    const reporttype = normalizeDropdown(
        inputData["Report Type"],
        {
            lab: ["lab", "blood", "cbc", "test"],
            radiology: ["x-ray", "mri", "ct", "scan"],
            scan: ["scan", "ultrasound"],
            other: ["other"]
        }
    );

    const followuprequired = normalizeDropdown(
        inputData["Follow-up Required"],
        {
            yes: ["yes"],
            no: ["no"]
        }
    );

    // STEP 4: Output

    return {
        patientid,
        testname,
        testdate,
        referringdoctor,
        resultsummary,
        detailedresultlongtext, // ✅ updated key here
        normalrange,
        resultstatus,
        technicianname,
        reportgenerateddate,
        reporttype,
        followuprequired
    };

} catch (error) {

    return {
        error: error.message
    };

}
